class Solution {
    public boolean canConstruct(String s, int k) {
        int[] count = new int[26];
        for (char c : s.toCharArray()) {
            count[c - 'a']++;
        }
        for (int i = 0; i < k; i++) {
            int sum = 0;
            for (int j = 0; j < k; j++) {
                sum += count[j];
            }
            if (sum % 2 != 0) {
                return false;
            }
            for (int j = 0; j < k; j++) {
                count[j]--;
            }
        }
        return true;
    }
}
```

